+func decodePartBody(p *gmail.MessagePart) (string, error) {
+	if p == nil || p.Body == nil || p.Body.Data == "" {
+		return "", nil
+	}
+	raw, err := decodeBase64URLBytes(p.Body.Data)
+	if err != nil {
+		return "", err
+	}
