+	charsetLabel := strings.TrimSpace(params["charset"])
+	if charsetLabel == "" || strings.EqualFold(charsetLabel, "utf-8") {
+		return data
+	}
+	reader, err := charset.NewReaderLabel(charsetLabel, bytes.NewReader(data))
+	if err != nil {
+		return data
+	}
+	decoded, err := io.ReadAll(reader)
 	if err != nil {
