+	return decoded
+}
+
+func looksLikeBase64(data []byte) bool {
+	trimmed := bytes.TrimSpace(data)
+	if len(trimmed) == 0 {
+		return false
+	}
+	for _, b := range trimmed {
+		switch {
+		case b >= 'A' && b <= 'Z':
+		case b >= 'a' && b <= 'z':
+		case b >= '0' && b <= '9':
+		case b == '+', b == '/', b == '=', b == '-', b == '_':
+		case b == '\n', b == '\r', b == '\t', b == ' ':
+		default:
+			return false
+		}
+	}
+	return true
+}
+
+func decodeAnyBase64(data []byte) ([]byte, error) {
+	cleaned := stripBase64Whitespace(data)
+	str := string(cleaned)
+	if decoded, err := base64.StdEncoding.DecodeString(str); err == nil {
+		return decoded, nil
+	}
+	if decoded, err := base64.RawStdEncoding.DecodeString(str); err == nil {
+		return decoded, nil
+	}
+	if decoded, err := base64.URLEncoding.DecodeString(str); err == nil {
+		return decoded, nil
+	}
+	return base64.RawURLEncoding.DecodeString(str)
+}
+
+func stripBase64Whitespace(data []byte) []byte {
+	out := make([]byte, 0, len(data))
+	for _, b := range data {
+		switch b {
+		case '\n', '\r', '\t', ' ':
+			continue
+		default:
+			out = append(out, b)
 		}
 	}
+	return out
+}
+
+func decodeBase64URLBytes(s string) ([]byte, error) {
+	if b, err := base64.RawURLEncoding.DecodeString(s); err == nil {
+		return b, nil
+	}
+	if b, err := base64.URLEncoding.DecodeString(s); err == nil {
+		return b, nil
+	}
+	if b, err := base64.RawStdEncoding.DecodeString(s); err == nil {
+		return b, nil
+	}
+	return base64.StdEncoding.DecodeString(s)
+}
+
+func decodeBase64URL(s string) (string, error) {
+	b, err := decodeBase64URLBytes(s)
+	if err != nil {
+		return "", err
+	}
 	return string(b), nil
 }

